contacts = {
    "Alice Smith":  {"phone": "555-0100"},
    "Alice Johnson": {"phone": "555-0200"},
    "Bob Brown":    {"phone": "555-0300"}
}

def search(contacts, query):
    query = query.lower()
    results = {name: info for name, info in contacts.items()
               if query in name.lower()}
    return results

found = search(contacts, "alice")
for name, info in found.items():
    print(f"{name}: {info['phone']}")

