exercises.solution:
def search_contacts(book, query):
    query = query.lower()
    return [name for name in book if query in name.lower()]

contacts = {
    "Alice": {"phone": "555-0100"},
    "Albert": {"phone": "555-0150"},
    "Bob": {"phone": "555-0200"}
}

results = search_contacts(contacts, "al")
print(results)
